10→import { IS_PUBLIC_KEY } from '@modules/auth/decorators/public.decorator';
11→import { IJwtPayload, IRequestUser } from '@modules/auth/types/auth.interface';
12→import { SessionService } from '@modules/session/session.service';
13→
14→@Injectable()
15→export class AuthGuard implements CanActivate {
16→	constructor(
17→		private readonly jwtService: JwtService,
18→		private readonly sessionService: SessionService,
19→		private readonly reflector: Reflector,
20→	) {}
21→
22→	async canActivate(context: ExecutionContext): Promise<boolean> {
23→		const isPublic = this.reflector.getAllAndOverride<boolean>(IS_PUBLIC_KEY, [
24→			context.getHandler(),
25→			context.getClass(),
26→		]);
27→		if (isPublic) return true;
28→
29→		const request = context.switchToHttp().getRequest();
30→		const token = this.extractTokenFromHeader(request);
31→		if (!token) throw new UnauthorizedException();
32→
33→		let payload: IJwtPayload;
34→		try {
35→			payload = await this.jwtService.verifyAsync<IJwtPayload>(token);
36→		} catch {
37→			throw new UnauthorizedException();
38→		}
39→
40→		const session = await this.sessionService.getSession({
41→			userId: payload.user_id,
42→			sessionId: payload.session_id,
43→		});
44→		if (!session) throw new UnauthorizedException();
45→
46→		request.user = {
47→			user_id: payload.user_id,
48→			session_id: payload.session_id,
49→			role: session.role,
50→			company_id: session.company_id,
51→		} satisfies IRequestUser;
52→
53→		return true;
54→	}
55→
56→	private extractTokenFromHeader(request: any): string | null {
57→		const [type, token] = request.headers?.authorization?.split(' ') ?? [];
58→		return type === 'Bearer' ? (token ?? null) : null;
59→	}
60→}
