15→
16→	canActivate(context: ExecutionContext): boolean {
17→		const requiredRoles = this.reflector.getAllAndOverride<('admin' | 'member')[]>(
18→			ROLES_KEY,
19→			[context.getHandler(), context.getClass()],
20→		);
21→
22→		if (!requiredRoles || requiredRoles.length === 0) return true;
23→
24→		const request = context.switchToHttp().getRequest();
25→		const user: IRequestUser | undefined = request.user;
